+                                            <button class="btn btn-outline-secondary btn-sm" disabled="@isBusy"
+                                                    @onclick="() => MoveTask(task.Id, columns[colIndex + 1].Status)">
+                                                Move Right &rarr;
+                                            </button>
+                                        }
+                                    </div>
+                                </div>
+                            </div>
+                        }
+
+                        @if (addingToColumn == column.Status)
+                        {
+                            <div class="card border-primary mb-2">
+                                <div class="card-body p-2">
+                                    <input type="text" class="form-control form-control-sm mb-1" placeholder="Title" @bind="newTitle" />
+                                    <input type="text" class="form-control form-control-sm mb-1" placeholder="Assignee" @bind="newAssignee" />
+                                    <select class="form-select form-select-sm mb-1" @bind="newPriority">
+                                        <option value="High">High</option>
+                                        <option value="Medium">Medium</option>
+                                        <option value="Low">Low</option>
+                                    </select>
+                                    <input type="date" class="form-control form-control-sm mb-1" @bind="newDueDate" />
+                                    <div class="d-flex gap-1">
+                                        <button class="btn btn-primary btn-sm" disabled="@isBusy" @onclick="SaveNewTask">Save</button>
+                                        <button class="btn btn-secondary btn-sm" @onclick="CancelAdd">Cancel</button>
+                                    </div>
+                                </div>
+                            </div>
+                        }
+                    </div>
+                    <div class="card-footer p-2">
+                        <button class="btn btn-outline-primary btn-sm w-100" @onclick="() => StartAdd(column.Status)">+ Add Task</button>
+                    </div>
+                </div>
+            </div>
+        }
+    </div>
+}
+
+@code {
+    private record ColumnDef(string Name, string Status);
+
+    private readonly ColumnDef[] columns =
+    [
+        new("To Do", "To Do"),
+        new("In Progress", "In Progress"),
+        new("Done", "Done")
+    ];
+
+    private List<TaskItem>? allTasks;
+    private string? errorMessage;
+    private string searchText = string.Empty;
+    private bool isBusy;
+
+    // Add-task form state
+    private string? addingToColumn;
+    private string newTitle = string.Empty;
+    private string newAssignee = string.Empty;
+    private string newPriority = "Medium";
+    private DateTime newDueDate = DateTime.Today.AddDays(7);
+
+    private List<TaskItem> TodoTasks => allTasks!.Where(t => t.Status == "To Do").ToList();
+    private List<TaskItem> InProgressTasks => allTasks!.Where(t => t.Status == "In Progress").ToList();
+    private List<TaskItem> DoneTasks => allTasks!.Where(t => t.Status == "Done").ToList();
+    private int OverdueCount => allTasks!.Count(t => t.DueDate < DateTime.Today);
+
+    protected override async Task OnInitializedAsync()
+    {
+        try
+        {
+            allTasks = await TaskService.GetAllTasksAsync();
+        }
+        catch (Exception ex)
+        {
+            errorMessage = $"Failed to load tasks: {ex.Message}";
+        }
+    }
+
+    private List<TaskItem> GetFilteredTasks(string status)
+    {
+        var tasks = allTasks!.Where(t => t.Status == status);
+        if (!string.IsNullOrWhiteSpace(searchText))
+        {
+            tasks = tasks.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase));
+        }
+        return tasks.ToList();
+    }
+
+    private static string GetPriorityClass(string priority) => priority switch
+    {
+        "High" => "bg-danger",
+        "Medium" => "bg-warning text-dark",
+        "Low" => "bg-success",
+        _ => "bg-secondary"
+    };
+
+    private async Task MoveTask(int taskId, string newStatus)
+    {
+        isBusy = true;
+        try
+        {
+            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
+            var task = allTasks!.First(t => t.Id == taskId);
+            allTasks![allTasks.IndexOf(task)] = task with { Status = newStatus };
+        }
+        catch (Exception ex)
+        {
+            errorMessage = $"Failed to move task: {ex.Message}";
+        }
+        finally
+        {
+            isBusy = false;
+        }
+    }
+
+    private void StartAdd(string status)
+    {
+        addingToColumn = status;
+        newTitle = string.Empty;
+        newAssignee = string.Empty;
+        newPriority = "Medium";
+        newDueDate = DateTime.Today.AddDays(7);
+    }
+
+    private void CancelAdd() => addingToColumn = null;
+
+    private async Task SaveNewTask()
+    {
+        if (string.IsNullOrWhiteSpace(newTitle) || addingToColumn is null) return;
+
+        isBusy = true;
+        try
+        {
+            var created = await TaskService.CreateTaskAsync(newTitle, newAssignee, newPriority, newDueDate);
+            // The service creates with default status; update if the target column differs
+            if (created.Status != addingToColumn)
+            {
+                await TaskService.UpdateTaskStatusAsync(created.Id, addingToColumn);
+                created = created with { Status = addingToColumn };
+            }
+            allTasks!.Add(created);
+            addingToColumn = null;
+        }
+        catch (Exception ex)
+        {
+            errorMessage = $"Failed to create task: {ex.Message}";
+        }
+        finally
+        {
+            isBusy = false;
+        }
+    }
+}
